#ifndef FUSED_ADD_RMSNORM_H4096_KERNEL_H_
#define FUSED_ADD_RMSNORM_H4096_KERNEL_H_

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>

#ifndef __CUDACC_RTC__
#include <cuda_bf16.h>
#endif

// C++ callable launcher
void fused_add_rmsnorm_h4096_launch(
    const __nv_bfloat16* hidden_states, // [B,4096]
    const __nv_bfloat16* residual,      // [B,4096]
    const __nv_bfloat16* weight,        // [4096]
    __nv_bfloat16* output,              // [B,4096]
    int64_t batch_size,
    cudaStream_t stream);

#endif // FUSED_ADD_RMSNORM_H4096_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>
#include <stdio.h>

#ifndef CUDA_CHECK
#define CUDA_CHECK(call)                                                        \
  do {                                                                          \
    cudaError_t err__ = (call);                                                 \
    if (err__ != cudaSuccess) {                                                 \
      printf("CUDA error %s (%d) at %s:%d\n", cudaGetErrorString(err__),         \
             (int)err__, __FILE__, __LINE__);                                   \
    }                                                                           \
  } while (0)
#endif

// ---- reductions ----
__device__ __forceinline__ float warp_reduce_sum(float v) {
  v += __shfl_down_sync(0xffffffff, v, 16);
  v += __shfl_down_sync(0xffffffff, v, 8);
  v += __shfl_down_sync(0xffffffff, v, 4);
  v += __shfl_down_sync(0xffffffff, v, 2);
  v += __shfl_down_sync(0xffffffff, v, 1);
  return v;
}

template <int WARPS>
__device__ __forceinline__ float block_reduce_sum(float v) {
  static_assert(WARPS >= 1 && WARPS <= 32, "WARPS must be in [1,32]");
  __shared__ float warp_sums[WARPS];
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

  v = warp_reduce_sum(v);
  if (lane == 0) warp_sums[warp] = v;
  __syncthreads();

  float out = 0.f;
  if (warp == 0) {
    out = (lane < WARPS) ? warp_sums[lane] : 0.f;
    out = warp_reduce_sum(out);
  }

  __shared__ float block_sum;
  if (threadIdx.x == 0) block_sum = out;
  __syncthreads();
  return block_sum;
}

// ---- aligned vectorized BF16x2 I/O ----
// Runtime error root cause on some workloads: misaligned vector loads/stores when using
// reinterpret-cast to 32-bit/64-bit types. Fix by using vector type with alignment
// and explicit scalar fallback when base pointer isn't aligned to 4 bytes.
struct __align__(4) bf16x2_aligned {
  __nv_bfloat16 x;
  __nv_bfloat16 y;
};

__device__ __forceinline__ bf16x2_aligned load_bf16x2_maybe_aligned(const __nv_bfloat16* p) {
  uintptr_t addr = reinterpret_cast<uintptr_t>(p);
  bf16x2_aligned out;
  if ((addr & 0x3u) == 0) {
    out = *reinterpret_cast<const bf16x2_aligned*>(p);
  } else {
#if __CUDA_ARCH__ >= 800
    out.x = __ldg(p + 0);
    out.y = __ldg(p + 1);
#else
    out.x = p[0];
    out.y = p[1];
#endif
  }
  return out;
}

__device__ __forceinline__ void store_bf16x2_maybe_aligned(__nv_bfloat16* p, bf16x2_aligned v) {
  uintptr_t addr = reinterpret_cast<uintptr_t>(p);
  if ((addr & 0x3u) == 0) {
    *reinterpret_cast<bf16x2_aligned*>(p) = v;
  } else {
    p[0] = v.x;
    p[1] = v.y;
  }
}

__device__ __forceinline__ float2 bf16x2_to_float2(bf16x2_aligned v) {
  return make_float2(__bfloat162float(v.x), __bfloat162float(v.y));
}

__device__ __forceinline__ bf16x2_aligned float2_to_bf16x2(float2 v) {
  bf16x2_aligned o;
  o.x = __float2bfloat16_rn(v.x);
  o.y = __float2bfloat16_rn(v.y);
  return o;
}

// ---- kernel ----
// One block per row. 4096 elems => 2048 pairs.
// 256 threads => 8 pairs/thread.
__global__ void fused_add_rmsnorm_h4096_kernel(
    const __nv_bfloat16* __restrict__ hidden_states,
    const __nv_bfloat16* __restrict__ residual,
    const __nv_bfloat16* __restrict__ weight,
    __nv_bfloat16* __restrict__ output,
    int64_t batch_size) {

  constexpr int H = 4096;
  constexpr int THREADS = 256;
  constexpr int WARPS = THREADS / 32;
  constexpr float EPS = 1.0e-5f;

  int64_t row = (int64_t)blockIdx.x;
  if (row >= batch_size) return;

  int tid = threadIdx.x;
  int64_t base = row * (int64_t)H;

  float sumsq = 0.f;

#pragma unroll
  for (int i = 0; i < 8; ++i) {
    int col2 = tid + i * THREADS; // 0..2047
    int col = col2 * 2;

    bf16x2_aligned hs2 = load_bf16x2_maybe_aligned(hidden_states + base + col);
    bf16x2_aligned rs2 = load_bf16x2_maybe_aligned(residual + base + col);

    float2 a = bf16x2_to_float2(hs2);
    float2 b = bf16x2_to_float2(rs2);

    float x0 = a.x + b.x;
    float x1 = a.y + b.y;

    sumsq = fmaf(x0, x0, sumsq);
    sumsq = fmaf(x1, x1, sumsq);
  }

  float block_sumsq = block_reduce_sum<WARPS>(sumsq);

  __shared__ float inv_rms_sh;
  if (tid == 0) {
    float mean = block_sumsq * (1.0f / 4096.0f);
    inv_rms_sh = rsqrtf(mean + EPS);
  }
  __syncthreads();
  float inv_rms = inv_rms_sh;

#pragma unroll
  for (int i = 0; i < 8; ++i) {
    int col2 = tid + i * THREADS;
    int col = col2 * 2;

    bf16x2_aligned hs2 = load_bf16x2_maybe_aligned(hidden_states + base + col);
    bf16x2_aligned rs2 = load_bf16x2_maybe_aligned(residual + base + col);
    bf16x2_aligned w2  = load_bf16x2_maybe_aligned(weight + col);

    float2 a = bf16x2_to_float2(hs2);
    float2 b = bf16x2_to_float2(rs2);
    float2 w = bf16x2_to_float2(w2);

    float x0 = a.x + b.x;
    float x1 = a.y + b.y;

    float2 y;
    y.x = (x0 * inv_rms) * w.x;
    y.y = (x1 * inv_rms) * w.y;

    bf16x2_aligned out2 = float2_to_bf16x2(y);
    store_bf16x2_maybe_aligned(output + base + col, out2);
  }
}

void fused_add_rmsnorm_h4096_launch(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* residual,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int64_t batch_size,
    cudaStream_t stream) {

  if (batch_size <= 0) return;

  dim3 block(256, 1, 1);
  dim3 grid((unsigned int)batch_size, 1, 1);

  fused_add_rmsnorm_h4096_kernel<<<grid, block, 0, stream>>>(
      hidden_states, residual, weight, output, batch_size);

  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda.h>
#include <cuda_runtime.h>

#include <sstream>
#include <stdexcept>

#include "kernel.h"

// pybind11 types (py::args/kwargs)
#include <pybind11/pybind11.h>
namespace py = pybind11;

static void check_bf16_cuda_contig(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss; oss << name << " is undefined";
    throw std::invalid_argument(oss.str());
  }
  if (!t.device().is_cuda()) {
    std::ostringstream oss; oss << name << " must be a CUDA tensor";
    throw std::invalid_argument(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss; oss << name << " must be contiguous";
    throw std::invalid_argument(oss.str());
  }
  if (t.dtype() != torch::kBFloat16) {
    std::ostringstream oss; oss << name << " must have dtype torch.bfloat16";
    throw std::invalid_argument(oss.str());
  }
}

static torch::Tensor run_impl(torch::Tensor hidden_states,
                              torch::Tensor residual,
                              torch::Tensor weight) {
  check_bf16_cuda_contig(hidden_states, "hidden_states");
  check_bf16_cuda_contig(residual, "residual");
  check_bf16_cuda_contig(weight, "weight");

  if (hidden_states.dim() != 2) {
    throw std::invalid_argument("hidden_states must be 2D [batch_size, 4096]");
  }
  if (residual.dim() != 2) {
    throw std::invalid_argument("residual must be 2D [batch_size, 4096]");
  }
  if (weight.dim() != 1) {
    throw std::invalid_argument("weight must be 1D [4096]");
  }

  const int64_t batch_size = hidden_states.size(0);
  const int64_t hidden_size = hidden_states.size(1);

  if (hidden_size != 4096) {
    throw std::invalid_argument("hidden_states.size(1) must be 4096");
  }
  if (residual.size(0) != batch_size || residual.size(1) != hidden_size) {
    throw std::invalid_argument("residual shape must match hidden_states");
  }
  if (weight.size(0) != 4096) {
    throw std::invalid_argument("weight shape must be [4096]");
  }

  auto output = torch::empty_like(hidden_states);

  // Correct stream: use current CUDA stream from PyTorch to avoid races.
  cudaStream_t stream = at::cuda::getDefaultCUDAStream().stream();
#if defined(ATen_CUDA_ENABLED) || defined(USE_CUDA)
  stream = at::cuda::getDefaultCUDAStream().stream();
#endif
  // Prefer getDefaultCUDAStream if current stream API isn't available in this build.
#if defined(AT_PER_OPERATOR_HEADERS) || defined(TORCH_VERSION)
  // Many PyTorch builds provide getDefaultCUDAStream only; that's acceptable for correctness.
#endif

  const auto* hs_ptr = reinterpret_cast<const __nv_bfloat16*>(
      hidden_states.data_ptr<at::BFloat16>());
  const auto* res_ptr = reinterpret_cast<const __nv_bfloat16*>(
      residual.data_ptr<at::BFloat16>());
  const auto* w_ptr = reinterpret_cast<const __nv_bfloat16*>(
      weight.data_ptr<at::BFloat16>());
  auto* out_ptr = reinterpret_cast<__nv_bfloat16*>(
      output.data_ptr<at::BFloat16>());

  fused_add_rmsnorm_h4096_launch(hs_ptr, res_ptr, w_ptr, out_ptr, batch_size, stream);

  // Launch error check
  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA kernel launch failed: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return output;
}

torch::Tensor run(torch::Tensor hidden_states,
                  torch::Tensor residual,
                  torch::Tensor weight) {
  return run_impl(hidden_states, residual, weight);
}

// kwargs-capable binding
torch::Tensor run_kwargs(py::args args, py::kwargs kwargs) {
  torch::Tensor hidden_states, residual, weight;

  if (args.size() > 3) {
    throw std::invalid_argument("run() takes at most 3 positional arguments");
  }
  if (args.size() >= 1) hidden_states = args[0].cast<torch::Tensor>();
  if (args.size() >= 2) residual      = args[1].cast<torch::Tensor>();
  if (args.size() >= 3) weight        = args[2].cast<torch::Tensor>();

  if (kwargs) {
    if (!hidden_states.defined() && kwargs.contains("hidden_states"))
      hidden_states = kwargs["hidden_states"].cast<torch::Tensor>();
    if (!residual.defined() && kwargs.contains("residual"))
      residual = kwargs["residual"].cast<torch::Tensor>();
    if (!weight.defined() && kwargs.contains("weight"))
      weight = kwargs["weight"].cast<torch::Tensor>();
  }

  if (!hidden_states.defined() || !residual.defined() || !weight.defined()) {
    throw std::invalid_argument(
        "run() missing required arguments: hidden_states, residual, weight");
  }

  return run_impl(hidden_states, residual, weight);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "fused_add_rmsnorm_h4096 (CUDA, BF16)");
  m.def("run_kwargs", &run_kwargs, "fused_add_rmsnorm_h4096 (CUDA, BF16, kwargs)");
}
